using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // FIX 1 – HasIndex throws in EF Core 9 Cosmos (was silently ignored in 8).
            //          Removed: entity.HasIndex(b => b.Name);
            //          Cosmos DB manages indexes via indexing policy, not EF.

            // FIX 2 – Discriminator property renamed from "Discriminator" to "$type" in EF 9.
            //          Keep the old name so existing documents are still readable.
            entity.HasDiscriminator<string>("Discriminator");

            // FIX 3 – Cosmos id value no longer includes the discriminator prefix.
            //          EF 8 generated id = "Blog|1"; EF 9 generates id = "1".
            //          Restore the old format so existing documents stay accessible.
            entity.Property("__id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "{Discriminator}|{Key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue();
        var keyProperty = entry.Metadata.FindPrimaryKey()!.Properties[0];
        var keyValue = entry.Property(keyProperty).CurrentValue;
        return $"{discriminator}|{keyValue}";
    }
}

